module tcp_segmentation(input [15:0] obf_data_in, output reg [3:0] seg_type);  
    always @(*) begin  
        if (obf_data_in < 512)  
            seg_type = 4'b0001;  
        else if (obf_data_in <= 1024)  
            seg_type = 4'b0010;  
        else  
            seg_type = 4'b0011;  
    end  
endmodule
